const ethers = require('ethers');

// Wallet Configuration
const provider = new ethers.providers.InfuraProvider('mainnet', 'YOUR_INFURA_PROJECT_ID');
const wallet = new ethers.Wallet('YOUR_PRIVATE_KEY', provider);

// Function to send ETH
async function sendETH(to, amount) {
  try {
    const tx = {
      to: to,
      value: ethers.utils.parseEther(amount)
    };
    const transaction = await wallet.sendTransaction(tx);
    await transaction.wait();
    console.log('Transaction successful:', transaction.hash);
  } catch (error) {
    console.error('Error sending ETH:', error);
  }
}

// Function to interact with a smart contract
async function interactWithContract(contractAddress, abi, methodName, ...args) {
  try {
    const contract = new ethers.Contract(contractAddress, abi, wallet);
    const transaction = await contract[methodName](...args);
    await transaction.wait();
    console.log('Contract interaction successful:', transaction.hash);
  } catch (error) {
    console.error('Error interacting with contract:', error);
  }
}

